        <div class="content">
            <div class="results-section">
                <h2 class="section-title">Çekiliş Sonuçları</h2>
                <div id="drawResults">
                    <p>Henüz çekiliş yapılmadı. "Çekiliş Yap" butonuna tıklayarak başlayın.</p>
                </div>
            </div>

            <div class="frequency-section">
                <h2 class="section-title">Sayı Frekansları</h2>
                <div id="frequencyResults">
                    <p>Çekilişi bitirdikten sonra frekanslar burada görüntülenecektir.</p>
                </div>
            </div>
        </div>

        <footer>
            <p>Çekiliş Yapma Sayfası &copy; 2023 | Her çekilişte 1-90 arası 6 farklı rastgele sayı üretilir.</p>
        </footer>
    </div>

    <script>
        // Değişkenler
        let draws = [];
        let drawCount = 0;
        let frequencyData = {};

        // DOM elementleri
        const drawBtn = document.getElementById('drawBtn');
        const endBtn = document.getElementById('endBtn');
        const downloadBtn = document.getElementById('downloadBtn');
        const drawResults = document.getElementById('drawResults');
        const frequencyResults = document.getElementById('frequencyResults');
        const totalDrawsElement = document.getElementById('totalDraws');

        // 1-90 arası 6 benzersiz rastgele sayı üretme fonksiyonu
        function generateUniqueNumbers() {
            const numbers = new Set();
            while (numbers.size < 6) {
                const randomNumber = Math.floor(Math.random() * 90) + 1;
                numbers.add(randomNumber);
            }
            return Array.from(numbers);
        }

        // Çekiliş yapma işlevi
        function performDraw() {
            drawCount++;
            const numbers = generateUniqueNumbers();

            // Çekilişi kaydet
            const draw = {
                cekilisNo: drawCount,
                sayilar: numbers
            };

            draws.push(draw);

            // Çekiliş sonucunu görüntüle
            displayDrawResult(draw);

            // Toplam çekiliş sayısını güncelle
            totalDrawsElement.textContent = drawCount;

            // Frekans verilerini güncelle
            updateFrequencyData(numbers);
        }

        // Çekiliş sonucunu görüntüleme fonksiyonu
        function displayDrawResult(draw) {
            // İlk çekilişte mesajı kaldır
            if (drawCount === 1) {
                drawResults.innerHTML = '';
            }

            // Çekiliş öğesini oluştur
            const drawItem = document.createElement('div');
            drawItem.className = 'draw-item';

            const drawTitle = document.createElement('h3');
            drawTitle.textContent = `${draw.cekilisNo}. Çekiliş`;

            const numbersContainer = document.createElement('div');
            numbersContainer.className = 'draw-numbers';

            // Sayıları ekle
            draw.sayilar.forEach(number => {
                const numberElement = document.createElement('div');
                numberElement.className = 'number';
                numberElement.textContent = number;
                numbersContainer.appendChild(numberElement);
            });

            drawItem.appendChild(drawTitle);
            drawItem.appendChild(numbersContainer);

            // Çekiliş sonuçlarına ekle
            drawResults.appendChild(drawItem);

            // En son çekilişe scroll yap
            drawItem.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        }

        // Frekans verilerini güncelleme fonksiyonu
        function updateFrequencyData(numbers) {
            numbers.forEach(number => {
                if (frequencyData[number]) {
                    frequencyData[number]++;
                } else {
                    frequencyData[number] = 1;
                }
            });
        }

        // Frekans sonuçlarını görüntüleme fonksiyonu
        function displayFrequencyResults() {
            frequencyResults.innerHTML = '';

            if (Object.keys(frequencyData).length === 0) {
                frequencyResults.innerHTML = '<p>Henüz çekiliş yapılmadı.</p>';
                return;
            }

            // Sayıları sırala
            const sortedNumbers = Object.keys(frequencyData)
                .map(Number)
                .sort((a, b) => a - b);

            // Her sayı için frekans göstergesi oluştur
            sortedNumbers.forEach(number => {
                const frequencyItem = document.createElement('div');
                frequencyItem.className = 'frequency-item';

                const numberElement = document.createElement('div');
                numberElement.className = 'frequency-number';
                numberElement.textContent = number;

                const countElement = document.createElement('div');
                countElement.className = 'frequency-count';
                countElement.textContent = `${frequencyData[number]} kez`;

                frequencyItem.appendChild(numberElement);
                frequencyItem.appendChild(countElement);
                frequencyResults.appendChild(frequencyItem);
            });

            // İndirme butonunu göster
            downloadBtn.style.display = 'block';
            downloadBtn.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        }

        // JSON verisi oluşturma ve indirme fonksiyonu
        function downloadJSON() {
            // JSON verisini oluştur
            const jsonData = {
                cekilisler: draws
            };

            const jsonString = JSON.stringify(jsonData, null, 2);
            const blob = new Blob([jsonString], { type: 'application/json' });
            const url = URL.createObjectURL(blob);

            // İndirme linki oluştur
            const a = document.createElement('a');
            a.href = url;
            a.download = `cekilis-sonuclari-${new Date().toISOString().slice(0, 10)}.json`;
            document.body.appendChild(a);
            a.click();

            // Temizlik
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }

        // Olay dinleyicileri
        drawBtn.addEventListener('click', performDraw);

        endBtn.addEventListener('click', () => {
            if (drawCount === 0) {
                alert('Henüz çekiliş yapılmadı. Lütfen önce çekiliş yapın.');
                return;
            }

            displayFrequencyResults();
            alert(`Çekiliş tamamlandı! Toplam ${drawCount} çekiliş yapıldı. Frekans sonuçları görüntüleniyor.`);
        });

        downloadBtn.addEventListener('click', downloadJSON);

        // Klavye kısayolları
        document.addEventListener('keydown', (e) => {
            // Space tuşu ile çekiliş yapma
            if (e.code === 'Space' && e.target === document.body) {
                e.preventDefault();
                performDraw();
            }

            // Enter tuşu ile çekilişi bitirme
            if (e.code === 'Enter' && e.ctrlKey) {
                e.preventDefault();
                endBtn.click();
            }
        });

        // Sayfa yüklendiğinde ilk mesajlar
        window.addEventListener('load', () => {
            console.log('Çekiliş sayfası hazır!');
        });
    </script>
</body>
