    <div class="container">
        <h1>Sayısal Çekiliş</h1>

        <div class="button-group">
            <button id="drawBtn" onclick="makeDraw()">Çekiliş Yap</button>
            <button id="finishBtn" onclick="finishDraws()">Çekilişi Bitir</button>
        </div>

        <div id="results"></div>

        <div id="frequencyReport">
            <h3>Frekans Raporu</h3>
            <div id="freqContent" class="freq-grid"></div>
        </div>

        <button id="downloadBtn" onclick="downloadJSON()">İndir</button>
    </div>

    <script>
        const drawsData = [];
        let drawCount = 0;

        function makeDraw() {
            drawCount++;
            const numbers = [];

            // 1-90 arası 6 farklı sayı üretimi
            while (numbers.length < 6) {
                const rand = Math.floor(Math.random() * 90) + 1;
                if (!numbers.includes(rand)) {
                    numbers.push(rand);
                }
            }

            // Sayıları küçükten büyüğe sırala (görsel düzen için)
            numbers.sort((a, b) => a - b);

            // Veriyi kaydet
            drawsData.push({
                cekilisNo: drawCount,
                sayilar: numbers
            });

            // Ekrana yazdır
            const resultsDiv = document.getElementById('results');
            const item = document.createElement('div');
            item.className = 'draw-item';
            item.innerText = `${drawCount}. Çekiliş: ${numbers.join(', ')}`;
            resultsDiv.appendChild(item);
        }

        function finishDraws() {
            if (drawsData.length === 0) {
                alert("Önce çekiliş yapmalısınız!");
                return;
            }

            // Frekans hesaplama
            const freqMap = {};
            drawsData.forEach(draw => {
                draw.sayilar.forEach(num => {
                    freqMap[num] = (freqMap[num] || 0) + 1;
                });
            });

            // Raporu oluşturma
            const freqContent = document.getElementById('freqContent');
            freqContent.innerHTML = '';

            // 1-90 arası tüm sayıları kontrol et, seçilenleri raporla
            for (let i = 1; i <= 90; i++) {
                if (freqMap[i]) {
                    const div = document.createElement('div');
                    div.className = 'freq-item';
                    div.innerHTML = `<strong>${i}:</strong> ${freqMap[i]} kez`;
                    freqContent.appendChild(div);
                }
            }

            // Arayüz güncellemeleri
            document.getElementById('frequencyReport').style.display = 'block';
            document.getElementById('downloadBtn').style.display = 'inline-block';
            document.getElementById('drawBtn').disabled = true;
            document.getElementById('finishBtn').disabled = true;
        }

        function downloadJSON() {
            const finalData = {
                cekilisler: drawsData
            };

            const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(finalData, null, 4));
            const downloadAnchorNode = document.createElement('a');
            downloadAnchorNode.setAttribute("href", dataStr);
            downloadAnchorNode.setAttribute("download", "cekilis_sonuclari.json");
            document.body.appendChild(downloadAnchorNode);
            downloadAnchorNode.click();
            downloadAnchorNode.remove();
        }
    </script>
</body>
