    </div>

    <script>
        // Veri Depolama
        let drawings = [];
        let currentDrawingCount = 0;

        // Frekansları tutmak için Map kullanıyoruz: Sayı -> Tekrar Sayısı
        let frequencyMap = new Map();

        // DOM Elemanları
        const drawButton = document.getElementById('drawButton');
        const finishButton = document.getElementById('finishButton');
        const downloadButton = document.getElementById('downloadButton');
        const resultsArea = document.getElementById('resultsArea');
        const frequencyReportArea = document.getElementById('frequencyReportArea');
        const frequencyList = document.getElementById('frequencyList');

        // --- Fonksiyonlar ---

        /**
         * 1 ile 90 arasında 6 adet rastgele sayı üretir.
         * @returns {number[]} 6 rastgele sayı dizisi
         */
        function generateRandomNumbers() {
            const numbers = [];
            for (let i = 0; i < 6; i++) {
                // 1 ile 90 arasında rastgele sayı
                numbers.push(Math.floor(Math.random() * 90) + 1);
            }
            // Sayıları sırala ve benzersiz hale getir (isteğe bağlı ama rastgelelik için sıralama iyidir)
            return numbers.sort((a, b) => a - b);
        }

        /**
         * Yeni bir çekiliş yapar ve sonucu ekranda gösterir.
         */
        function makeDrawing() {
            const drawnNumbers = generateRandomNumbers();
            currentDrawingCount++;

            // Sonuç formatı: "X. Çekiliş: S1, S2, S3, S4, S5, S6"
            const resultText = `${currentDrawingCount}. Çekiliş: ${drawnNumbers.join(', ')}`;

            // Sonucu ekle
            const resultDiv = document.createElement('div');
            resultDiv.className = 'drawing-result';
            resultDiv.innerHTML = resultText;

            resultsArea.appendChild(resultDiv);

            // Buton durumunu güncelle
            finishButton.disabled = false;

            // Eğer daha önce bitirilmediyse, frekans alanını gizle
            frequencyReportArea.style.display = 'none';
        }

        /**
         * Tüm çekilişleri bitirir, frekansları hesaplar ve raporu gösterir.
         */
        function finishDrawings() {
            if (drawings.length === 0) {
                alert("Lütfen önce bir çekiliş yapın.");
                return;
            }

            // 1. Frekans Hesaplama
            frequencyMap.clear();
            drawings.forEach(drawing => {
                drawing.sayilar.forEach(num => {
                    const key = num.toString();
                    frequencyMap.set(key, (frequencyMap.get(key) || 0) + 1);
                });
            });

            // 2. Frekansları HTML'de Gösterme
            displayFrequencyReport();

            // 3. İndir butonunu göster
            downloadButton.style.display = 'inline-block';
        }

        /**
         * Frekansları HTML üzerinde görüntüler.
         */
        function displayFrequencyReport() {
            frequencyList.innerHTML = '';

            if (frequencyMap.size === 0) {
                frequencyList.innerHTML = '<p>Henüz çekiliş verisi bulunmamaktadır.</p>';
                return;
            }

            // Frekansları sırala (Sayı bazında)
            const sortedFrequencies = Array.from(frequencyMap.entries())
                .sort((a, b) => parseInt(a[0]) - parseInt(b[0]));

            sortedFrequencies.forEach(([numberStr, count]) => {
                const p = document.createElement('p');
                p.textContent = `Sayı ${numberStr}: Toplam ${count} kez çekildi.`;
                frequencyList.appendChild(p);
            });

            // Frekans raporunu göster
            frequencyReportArea.style.display = 'block';
        }


        /**
         * Tüm veriyi JSON olarak oluşturur ve indirir.
         */
        function downloadJson() {
            if (drawings.length === 0) {
                alert("İndirilecek veri yok.");
                return;
            }

            const dataToDownload = {
                "cekilisler": drawings
            };

            // JSON formatına çevir
            const jsonString = JSON.stringify(dataToDownload, null, 4);

            // Blob oluştur ve indirme işlemini tetikle
            const blob = new Blob([jsonString], { type: 'application/json' });
            const url = URL.createObjectURL(blob);

            const a = document.createElement('a');
            a.href = url;
            a.download = `cekilis_sonuclari_${new Date().toISOString().slice(0, 10)}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }


        // --- Olay Dinleyicileri (Event Listeners) ---

        drawButton.addEventListener('click', makeDrawing);
        finishButton.addEventListener('click', finishDrawings);
        downloadButton.addEventListener('click', downloadJson);

        // Başlangıçta butonları ayarla
        finishButton.disabled = true;

    </script>

</body>
</html>
